    public Object parseTicker(Object ticker, Object... optionalArgs)
    {
        //
        //     {
        //         "last":"0.022902",
        //         "low":"0.021693",
        //         "high":"0.024093",
        //         "change":"-0.000047",
        //         "base_volume":"15681.986",
        //         "quote_volume":"360.514403624",
        //         "market_id":"ETH-BTC",
        //         "time":"2020-04-12T18:43:38.000Z"
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object timestamp = this.parse8601(this.safeString(ticker, "time"));
        Object marketId = this.safeString(ticker, "market_id");
        Object symbol = this.safeSymbol(marketId, market, "-");
        Object close = this.safeString(ticker, "last");
        Object change = this.safeString(ticker, "change");
        Object baseVolume = this.safeString(ticker, "base_volume");
        Object quoteVolume = this.safeString(ticker, "quote_volume");
        return this.safeTicker(new java.util.HashMap<String, Object>() {{
            put( "symbol", symbol );
            put( "timestamp", timestamp );
            put( "datetime", Probit.this.iso8601(timestamp) );
            put( "high", Probit.this.safeString(ticker, "high") );
            put( "low", Probit.this.safeString(ticker, "low") );
            put( "bid", null );
            put( "bidVolume", null );
            put( "ask", null );
            put( "askVolume", null );
            put( "vwap", null );
            put( "open", null );
            put( "close", close );
            put( "last", close );
            put( "previousClose", null );
            put( "change", change );
            put( "percentage", null );
            put( "average", null );
            put( "baseVolume", baseVolume );
            put( "quoteVolume", quoteVolume );
            put( "info", ticker );
        }}, market);
    }

