    public Object parseTrade(Object trade, Object... optionalArgs)
    {
        //
        // fetchTrades (public)
        //
        //     {
        //         "id":"ETH-BTC:3331886",
        //         "price":"0.022981",
        //         "quantity":"12.337",
        //         "time":"2020-04-12T20:55:42.371Z",
        //         "side":"sell",
        //         "tick_direction":"down"
        //     }
        //
        // fetchMyTrades (private)
        //
        //     {
        //         "id":"BTC-USDT:183566",
        //         "order_id":"17209376",
        //         "side":"sell",
        //         "fee_amount":"0.657396569175",
        //         "fee_currency_id":"USDT",
        //         "status":"settled",
        //         "price":"6573.96569175",
        //         "quantity":"0.1",
        //         "cost":"657.396569175",
        //         "time":"2018-08-10T06:06:46.000Z",
        //         "market_id":"BTC-USDT"
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object timestamp = this.parse8601(this.safeString(trade, "time"));
        Object id = this.safeString(trade, "id");
        Object marketId = null;
        if (Helpers.isTrue(!Helpers.isEqual(id, null)))
        {
            Object parts = Helpers.split(id, ":");
            marketId = this.safeString(parts, 0);
        }
        marketId = this.safeString(trade, "market_id", marketId);
        Object symbol = this.safeSymbol(marketId, market, "-");
        Object side = this.safeString(trade, "side");
        Object priceString = this.safeString(trade, "price");
        Object amountString = this.safeString(trade, "quantity");
        Object orderId = this.safeString(trade, "order_id");
        Object feeCostString = this.safeString(trade, "fee_amount");
        Object fee = null;
        if (Helpers.isTrue(!Helpers.isEqual(feeCostString, null)))
        {
            Object feeCurrencyId = this.safeString(trade, "fee_currency_id");
            Object feeCurrencyCode = this.safeCurrencyCode(feeCurrencyId);
            final Object finalFeeCostString = feeCostString;
            fee = new java.util.HashMap<String, Object>() {{
                put( "cost", finalFeeCostString );
                put( "currency", feeCurrencyCode );
            }};
        }
        final Object finalId = id;
        final Object finalFee = fee;
        return this.safeTrade(new java.util.HashMap<String, Object>() {{
            put( "id", finalId );
            put( "info", trade );
            put( "timestamp", timestamp );
            put( "datetime", Probit.this.iso8601(timestamp) );
            put( "symbol", symbol );
            put( "order", orderId );
            put( "type", null );
            put( "side", side );
            put( "takerOrMaker", null );
            put( "price", priceString );
            put( "amount", amountString );
            put( "cost", null );
            put( "fee", finalFee );
        }}, market);
    }

