    public Object normalizeOHLCVTimestamp(Object timestamp, Object timeframe, Object... optionalArgs)
    {
        Object after = Helpers.getArg(optionalArgs, 0, false);
        Object duration = this.parseTimeframe(timeframe);
        if (Helpers.isTrue(Helpers.isEqual(timeframe, "1M")))
        {
            Object iso8601 = this.iso8601(timestamp);
            Object parts = Helpers.split(iso8601, "-");
            Object year = this.safeString(parts, 0);
            Object month = this.safeInteger(parts, 1);
            Object monthString = null;
            if (Helpers.isTrue(after))
            {
                monthString = String.valueOf(this.sum(month, 1));
            }
            if (Helpers.isTrue(Helpers.isLessThan(month, 10)))
            {
                monthString = Helpers.add("0", String.valueOf(month));
            }
            return Helpers.add(Helpers.add(Helpers.add(year, "-"), monthString), "-01T00:00:00.000Z");
        } else if (Helpers.isTrue(Helpers.isEqual(timeframe, "1w")))
        {
            timestamp = this.parseToInt(Helpers.divide(timestamp, 1000));
            Object firstSunday = 259200; // 1970-01-04T00:00:00.000Z
            Object difference = Helpers.subtract(timestamp, firstSunday);
            Object numWeeks = (Math.floor(Double.parseDouble(Helpers.toString(Helpers.divide(difference, duration)))));
            Object previousSunday = this.sum(firstSunday, Helpers.multiply(numWeeks, duration));
            if (Helpers.isTrue(after))
            {
                previousSunday = this.sum(previousSunday, duration);
            }
            return this.iso8601(Helpers.multiply(previousSunday, 1000));
        } else
        {
            timestamp = this.parseToInt(Helpers.divide(timestamp, 1000));
            timestamp = Helpers.multiply(duration, this.parseToInt(Helpers.divide(timestamp, duration)));
            if (Helpers.isTrue(after))
            {
                timestamp = this.sum(timestamp, duration);
            }
            return this.iso8601(Helpers.multiply(timestamp, 1000));
        }
    }

    /**
     * @method
     * @name probit#fetchOHLCV
     * @see https://docs-en.probit.com/reference/candle
     * @description fetches historical candlestick data containing the open, high, low, and close price, and the volume of a market
     * @param {string} symbol unified symbol of the market to fetch OHLCV data for
     * @param {string} timeframe the length of time each candle represents
     * @param {int} [since] timestamp in ms of the earliest candle to fetch
     * @param {int} [limit] the maximum amount of candles to fetch
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @param {string} [params.until] timestamp in ms of the earliest candle to fetch
     * @returns {int[][]} A list of candles ordered as timestamp, open, high, low, close, volume
     */
    public java.util.concurrent.CompletableFuture<Object> fetchOHLCV(Object symbol, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object timeframe = Helpers.getArg(optionalArgs, 0, "1m");
            Object since = Helpers.getArg(optionalArgs, 1, null);
            Object limit = Helpers.getArg(optionalArgs, 2, null);
            Object parameters = Helpers.getArg(optionalArgs, 3, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object market = this.market(symbol);
            Object interval = this.safeString(this.timeframes, timeframe, timeframe);
            limit = ((Helpers.isTrue((Helpers.isEqual(limit, null))))) ? 100 : limit;
            Object requestLimit = this.sum(limit, 1);
            requestLimit = Helpers.mathMin(1000, requestLimit); // max 1000
            final Object finalRequestLimit = requestLimit;
            Object request = new java.util.HashMap<String, Object>() {{
                put( "market_ids", Helpers.GetValue(market, "id") );
                put( "interval", interval );
                put( "sort", "asc" );
                put( "limit", finalRequestLimit );
            }};
            Object now = this.milliseconds();
            Object until = this.safeInteger(parameters, "until");
            Object durationMilliseconds = Helpers.multiply(this.parseTimeframe(timeframe), 1000);
            Object startTime = since;
            Object endTime = ((Helpers.isTrue((!Helpers.isEqual(until, null))))) ? Helpers.subtract(until, durationMilliseconds) : now;
            if (Helpers.isTrue(Helpers.isEqual(since, null)))
            {
                if (Helpers.isTrue(Helpers.isEqual(limit, null)))
                {
                    limit = requestLimit;
                }
                Object startLimit = Helpers.subtract(limit, 1);
                startTime = Helpers.subtract(endTime, Helpers.multiply(startLimit, durationMilliseconds));
            } else
            {
                if (Helpers.isTrue(!Helpers.isEqual(limit, null)))
                {
                    Object endByLimit = this.sum(since, Helpers.multiply(limit, durationMilliseconds));
                    endTime = Helpers.mathMin(endTime, endByLimit);
                }
            }
            Object startTimeNormalized = this.normalizeOHLCVTimestamp(startTime, timeframe);
            Object endTimeNormalized = this.normalizeOHLCVTimestamp(endTime, timeframe, true);
            Helpers.addElementToObject(request, "start_time", startTimeNormalized);
            Helpers.addElementToObject(request, "end_time", endTimeNormalized);
            Object response = (this.publicGetCandle(this.extend(request, parameters))).join();
            //
            //     {
            //         "data":[
            //             {
            //                 "market_id":"ETH-BTC",
            //                 "open":"0.02811",
            //                 "close":"0.02811",
            //                 "low":"0.02811",
            //                 "high":"0.02811",
            //                 "base_volume":"0.0005",
            //                 "quote_volume":"0.000014055",
            //                 "start_time":"2018-11-30T18:19:00.000Z",
            //                 "end_time":"2018-11-30T18:20:00.000Z"
            //             },
            //         ]
            //     }
            //
            Object data = this.safeList(response, "data", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            return this.parseOHLCVs(data, market, timeframe, since, limit);
        }, io.github.ccxt.Exchange.VIRTUAL_EXECUTOR);

    }

