    public Object parseOrderStatus(Object status)
    {
        Object statuses = new java.util.HashMap<String, Object>() {{
            put( "open", "open" );
            put( "cancelled", "canceled" );
            put( "filled", "closed" );
        }};
        return this.safeString(statuses, status, status);
    }

    public Object parseOrder(Object order, Object... optionalArgs)
    {
        //
        //     {
        //         id,
        //         user_id,
        //         market_id,
        //         "type": "orderType",
        //         "side": "side",
        //         quantity,
        //         limit_price,
        //         "time_in_force": "timeInForce",
        //         filled_cost,
        //         filled_quantity,
        //         open_quantity,
        //         cancelled_quantity,
        //         "status": "orderStatus",
        //         "time": "date",
        //         client_order_id,
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object status = this.parseOrderStatus(this.safeString(order, "status"));
        Object id = this.safeString(order, "id");
        Object type = this.safeString(order, "type");
        Object side = this.safeString(order, "side");
        Object marketId = this.safeString(order, "market_id");
        Object symbol = this.safeSymbol(marketId, market, "-");
        Object timestamp = this.parse8601(this.safeString(order, "time"));
        Object price = this.safeString(order, "limit_price");
        Object filled = this.safeString(order, "filled_quantity");
        Object remaining = this.safeString(order, "open_quantity");
        Object canceledAmount = this.safeString(order, "cancelled_quantity");
        if (Helpers.isTrue(!Helpers.isEqual(canceledAmount, null)))
        {
            remaining = Precise.stringAdd(remaining, canceledAmount);
        }
        Object amount = this.safeString(order, "quantity", Precise.stringAdd(filled, remaining));
        Object cost = this.safeString2(order, "filled_cost", "cost");
        if (Helpers.isTrue(Helpers.isEqual(type, "market")))
        {
            price = null;
        }
        Object clientOrderId = this.safeString(order, "client_order_id");
        Object timeInForce = this.safeStringUpper(order, "time_in_force");
        final Object finalType = type;
        final Object finalPrice = price;
        final Object finalRemaining = remaining;
        return this.safeOrder(new java.util.HashMap<String, Object>() {{
            put( "id", id );
            put( "info", order );
            put( "clientOrderId", clientOrderId );
            put( "timestamp", timestamp );
            put( "datetime", Probit.this.iso8601(timestamp) );
            put( "lastTradeTimestamp", null );
            put( "symbol", symbol );
            put( "type", finalType );
            put( "timeInForce", timeInForce );
            put( "side", side );
            put( "status", status );
            put( "price", finalPrice );
            put( "triggerPrice", null );
            put( "amount", amount );
            put( "filled", filled );
            put( "remaining", finalRemaining );
            put( "average", null );
            put( "cost", cost );
            put( "fee", null );
            put( "trades", null );
        }}, market);
    }

    public Object costToPrecision(Object symbol, Object cost)
    {
        return this.decimalToPrecision(cost, TRUNCATE, Helpers.GetValue(Helpers.GetValue(Helpers.GetValue(this.markets, symbol), "precision"), "cost"), this.precisionMode);
    }

    /**
     * @method
     * @name probit#createOrder
     * @description create a trade order
     * @see https://docs-en.probit.com/reference/order-1
     * @param {string} symbol unified symbol of the market to create an order in
     * @param {string} type 'market' or 'limit'
     * @param {string} side 'buy' or 'sell'
     * @param {float} amount how much you want to trade in units of the base currency
     * @param {float} [price] the price at which the order is to be fulfilled, in units of the quote currency, ignored in market orders
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @param {float} [params.cost] the quote quantity that can be used as an alternative for the amount for market buy orders
     * @returns {object} an [order structure]{@link https://docs.ccxt.com/?id=order-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> createOrder(Object symbol, Object type2, Object side2, Object amount, Object... optionalArgs)
    {
        final Object type3 = type2;
        final Object side3 = side2;
        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {
            Object type = type3;
            Object side = side3;
            Object price = Helpers.getArg(optionalArgs, 0, null);
            Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object market = this.market(symbol);
            Object options = this.safeValue(this.options, "timeInForce");
            Object defaultTimeInForce = this.safeValue(options, type);
            Object timeInForce = this.safeString2(parameters, "timeInForce", "time_in_force", defaultTimeInForce);
            Object request = new java.util.HashMap<String, Object>() {{
                put( "market_id", Helpers.GetValue(market, "id") );
                put( "type", type );
                put( "side", side );
                put( "time_in_force", timeInForce );
            }};
            Object clientOrderId = this.safeString2(parameters, "clientOrderId", "client_order_id");
            if (Helpers.isTrue(!Helpers.isEqual(clientOrderId, null)))
            {
                Helpers.addElementToObject(request, "client_order_id", clientOrderId);
            }
            Object quoteAmount = null;
            if (Helpers.isTrue(Helpers.isEqual(type, "limit")))
            {
                Helpers.addElementToObject(request, "limit_price", this.priceToPrecision(symbol, price));
                Helpers.addElementToObject(request, "quantity", this.amountToPrecision(symbol, amount));
            } else if (Helpers.isTrue(Helpers.isEqual(type, "market")))
            {
                // for market buy it requires the amount of quote currency to spend
                if (Helpers.isTrue(Helpers.isEqual(side, "buy")))
                {
                    Object createMarketBuyOrderRequiresPrice = true;
                    var createMarketBuyOrderRequiresPriceparametersVariable = this.handleOptionAndParams(parameters, "createOrder", "createMarketBuyOrderRequiresPrice", true);
                    createMarketBuyOrderRequiresPrice = ((java.util.List<Object>) createMarketBuyOrderRequiresPriceparametersVariable).get(0);
                    parameters = ((java.util.List<Object>) createMarketBuyOrderRequiresPriceparametersVariable).get(1);
                    Object cost = this.safeString(parameters, "cost");
                    parameters = this.omit(parameters, "cost");
                    if (Helpers.isTrue(!Helpers.isEqual(cost, null)))
                    {
                        quoteAmount = this.costToPrecision(symbol, cost);
                    } else if (Helpers.isTrue(createMarketBuyOrderRequiresPrice))
                    {
                        if (Helpers.isTrue(Helpers.isEqual(price, null)))
                        {
                            throw new InvalidOrder((String)Helpers.add(this.id, " createOrder() requires the price argument for market buy orders to calculate the total cost to spend (amount * price), alternatively set the createMarketBuyOrderRequiresPrice option or param to false and pass the cost to spend in the amount argument")) ;
                        } else
                        {
                            Object amountString = this.numberToString(amount);
                            Object priceString = this.numberToString(price);
                            Object costRequest = Precise.stringMul(amountString, priceString);
                            quoteAmount = this.costToPrecision(symbol, costRequest);
                        }
                    } else
                    {
                        quoteAmount = this.costToPrecision(symbol, amount);
                    }
                    Helpers.addElementToObject(request, "cost", quoteAmount);
                } else
                {
                    Helpers.addElementToObject(request, "quantity", this.amountToPrecision(symbol, amount));
                }
            }
            Object query = this.omit(parameters, new java.util.ArrayList<Object>(java.util.Arrays.asList("timeInForce", "time_in_force", "clientOrderId", "client_order_id")));
            Object response = (this.privatePostNewOrder(this.extend(request, query))).join();
            //
            //     {
            //         "data": {
            //             id,
            //             user_id,
            //             market_id,
            //             "type": "orderType",
            //             "side": "side",
            //             quantity,
            //             limit_price,
            //             "time_in_force": "timeInForce",
            //             filled_cost,
            //             filled_quantity,
            //             open_quantity,
            //             cancelled_quantity,
            //             "status": "orderStatus",
            //             "time": "date",
            //             client_order_id,
            //         }
            //     }
            //
            Object data = this.safeValue(response, "data");
            Object order = this.parseOrder(data, market);
            // a workaround for incorrect huge amounts
            // returned by the exchange on market buys
            if (Helpers.isTrue(Helpers.isTrue((Helpers.isEqual(type, "market"))) && Helpers.isTrue((Helpers.isEqual(side, "buy")))))
            {
                Helpers.addElementToObject(order, "amount", null);
                Helpers.addElementToObject(order, "cost", this.parseNumber(quoteAmount));
                Helpers.addElementToObject(order, "remaining", null);
            }
            return order;
        }, io.github.ccxt.Exchange.VIRTUAL_EXECUTOR);

    }

