    /**
     * @method
     * @name probit#fetchDepositAddress
     * @see https://docs-en.probit.com/reference/deposit_address
     * @description fetch the deposit address for a currency associated with this account
     * @param {string} code unified currency code
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} an [address structure]{@link https://docs.ccxt.com/?id=address-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> fetchDepositAddress(Object code, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object currency = this.currency(code);
            Object request = new java.util.HashMap<String, Object>() {{
                put( "currency_id", Helpers.GetValue(currency, "id") );
            }};
            Object networks = this.safeValue(this.options, "networks", new java.util.HashMap<String, Object>() {{}});
            Object network = this.safeStringUpper(parameters, "network"); // this line allows the user to specify either ERC20 or ETH
            network = this.safeString(networks, network, network); // handle ERC20>ETH alias
            if (Helpers.isTrue(!Helpers.isEqual(network, null)))
            {
                Helpers.addElementToObject(request, "platform_id", network);
                parameters = this.omit(parameters, "platform_id");
            }
            Object response = (this.privateGetDepositAddress(this.extend(request, parameters))).join();
            //
            // without 'platform_id'
            //     {
            //         "data":[
            //             {
            //                 "currency_id":"ETH",
            //                 "address":"0x12e2caf3c4051ba1146e612f532901a423a9898a",
            //                 "destination_tag":null
            //             }
            //         ]
            //     }
            //
            // with 'platform_id'
            //     {
            //         "data":[
            //             {
            //                 "platform_id":"TRON",
            //                 "address":"TDQLMxBTa6MzuoZ6deSGZkqET3Ek8v7uC6",
            //                 "destination_tag":null
            //             }
            //         ]
            //     }
            //
            Object data = this.safeValue(response, "data", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            Object firstAddress = this.safeValue(data, 0);
            if (Helpers.isTrue(Helpers.isEqual(firstAddress, null)))
            {
                throw new InvalidAddress((String)Helpers.add(this.id, " fetchDepositAddress() returned an empty response")) ;
            }
            return this.parseDepositAddress(firstAddress, currency);
        }, io.github.ccxt.Exchange.VIRTUAL_EXECUTOR);

    }

