            (this.loadMarkets()).join();
            Object request = new java.util.HashMap<String, Object>() {{}};
            if (Helpers.isTrue(codes))
            {
                Object currencyIds = new java.util.ArrayList<Object>(java.util.Arrays.asList());
                for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(codes)); i++)
                {
                    Object currency = this.currency(Helpers.GetValue(codes, i));
                    ((java.util.List<Object>)currencyIds).add(Helpers.GetValue(currency, "id"));
                }
                Helpers.addElementToObject(request, "currency_id", String.join((String)",", (java.util.List<String>)codes));
            }
            Object response = (this.privateGetDepositAddress(this.extend(request, parameters))).join();
            Object data = this.safeList(response, "data", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
