    public Object parseDepositWithdrawFee(Object fee, Object... optionalArgs)
    {
        //
        // {
        //     "id": "USDT",
        //     "display_name": { "ko-kr": '테더', "en-us": "Tether" },
        //     "show_in_ui": true,
        //     "platform": [
        //       {
        //         "id": "ETH",
        //         "priority": "1",
        //         "deposit": true,
        //         "withdrawal": true,
        //         "currency_id": "USDT",
        //         "precision": "6",
        //         "min_confirmation_count": "15",
        //         "require_destination_tag": false,
        //         "allow_withdrawal_destination_tag": false,
        //         "display_name": [Object],
        //         "min_deposit_amount": "0",
        //         "min_withdrawal_amount": "1",
        //         "withdrawal_fee": [Array],
        //         "deposit_fee": {},
        //         "suspended_reason": '',
        //         "deposit_suspended": false,
        //         "withdrawal_suspended": false,
        //         "platform_currency_display_name": [Object]
        //       },
        //     ],
        //     "internal_transfer": { suspended_reason: null, suspended: false },
        //     "stakeable": false,
        //     "unstakeable": false,
        //     "auto_stake": false,
        //     "auto_stake_amount": "0"
        //   }
        //
        Object currency = Helpers.getArg(optionalArgs, 0, null);
        Object depositWithdrawFee = this.depositWithdrawFee(new java.util.HashMap<String, Object>() {{}});
        Object platforms = this.safeValue(fee, "platform", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
        Object depositResult = new java.util.HashMap<String, Object>() {{
            put( "fee", null );
            put( "percentage", null );
        }};
        for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(platforms)); i++)
        {
            Object network = Helpers.GetValue(platforms, i);
            Object networkId = this.safeString(network, "id");
            Object networkCode = this.networkIdToCode(networkId, Helpers.GetValue(currency, "code"));
            Object withdrawalFees = this.safeValue(network, "withdrawal_fee", new java.util.HashMap<String, Object>() {{}});
            Object withdrawFee = this.safeNumber(Helpers.GetValue(withdrawalFees, 0), "amount");
            if (Helpers.isTrue(Helpers.getArrayLength(withdrawalFees)))
            {
                Object withdrawResult = new java.util.HashMap<String, Object>() {{
                    put( "fee", withdrawFee );
                    put( "percentage", ((Helpers.isTrue((!Helpers.isEqual(withdrawFee, null))))) ? false : null );
                }};
                if (Helpers.isTrue(Helpers.isEqual(i, 0)))
                {
                    Helpers.addElementToObject(depositWithdrawFee, "withdraw", withdrawResult);
                }
                Helpers.addElementToObject(Helpers.GetValue(depositWithdrawFee, "networks"), networkCode, new java.util.HashMap<String, Object>() {{
    put( "withdraw", withdrawResult );
    put( "deposit", depositResult );
}});
            }
        }
        Helpers.addElementToObject(depositWithdrawFee, "info", fee);
        return depositWithdrawFee;
    }

    public Object nonce()
    {
        return this.milliseconds();
    }

    public Object sign(Object path, Object... optionalArgs)
    {
        Object api = Helpers.getArg(optionalArgs, 0, "public");
        Object method = Helpers.getArg(optionalArgs, 1, "GET");
        Object parameters = Helpers.getArg(optionalArgs, 2, new java.util.HashMap<String, Object>() {{}});
        Object headers = Helpers.getArg(optionalArgs, 3, null);
        Object body = Helpers.getArg(optionalArgs, 4, null);
        Object url = Helpers.add(Helpers.GetValue(Helpers.GetValue(this.urls, "api"), api), "/");
        Object query = this.omit(parameters, this.extractParams(path));
        if (Helpers.isTrue(Helpers.isEqual(api, "accounts")))
        {
            this.checkRequiredCredentials();
            url = Helpers.add(url, this.implodeParams(path, parameters));
            Object auth = Helpers.add(Helpers.add(this.apiKey, ":"), this.secret);
            Object auth64 = this.stringToBase64(auth);
            headers = new java.util.HashMap<String, Object>() {{
                put( "Authorization", Helpers.add("Basic ", auth64) );
                put( "Content-Type", "application/json" );
            }};
            if (Helpers.isTrue(Helpers.getArrayLength(new java.util.ArrayList<Object>(((java.util.Map<String, Object>)query).keySet()))))
            {
                body = this.json(query);
            }
        } else
        {
            url = Helpers.add(url, Helpers.add(this.version, "/"));
            if (Helpers.isTrue(Helpers.isEqual(api, "public")))
            {
                url = Helpers.add(url, this.implodeParams(path, parameters));
                if (Helpers.isTrue(Helpers.getArrayLength(new java.util.ArrayList<Object>(((java.util.Map<String, Object>)query).keySet()))))
                {
                    url = Helpers.add(url, Helpers.add("?", this.urlencode(query)));
                }
            } else if (Helpers.isTrue(Helpers.isEqual(api, "private")))
            {
                Object now = this.milliseconds();
                this.checkRequiredCredentials();
                Object expires = this.safeInteger(this.options, "expires");
                if (Helpers.isTrue(Helpers.isTrue((Helpers.isEqual(expires, null))) || Helpers.isTrue((Helpers.isLessThan(expires, now)))))
                {
                    throw new AuthenticationError((String)Helpers.add(this.id, " access token expired, call signIn() method")) ;
                }
                Object accessToken = this.safeString(this.options, "accessToken");
                headers = new java.util.HashMap<String, Object>() {{
                    put( "Authorization", Helpers.add("Bearer ", accessToken) );
                }};
                url = Helpers.add(url, this.implodeParams(path, parameters));
                if (Helpers.isTrue(Helpers.isEqual(method, "GET")))
                {
                    if (Helpers.isTrue(Helpers.getArrayLength(new java.util.ArrayList<Object>(((java.util.Map<String, Object>)query).keySet()))))
                    {
                        url = Helpers.add(url, Helpers.add("?", this.urlencode(query)));
                    }
                } else if (Helpers.isTrue(Helpers.getArrayLength(new java.util.ArrayList<Object>(((java.util.Map<String, Object>)query).keySet()))))
                {
                    body = this.json(query);
                    Helpers.addElementToObject(headers, "Content-Type", "application/json");
                }
            }
        }
        final Object finalUrl = url;
        final Object finalMethod = method;
        final Object finalBody = body;
        final Object finalHeaders = headers;
        return new java.util.HashMap<String, Object>() {{
            put( "url", finalUrl );
            put( "method", finalMethod );
            put( "body", finalBody );
            put( "headers", finalHeaders );
        }};
    }

    /**
     * @method
     * @name probit#signIn
     * @see https://docs-en.probit.com/reference/token
     * @description sign in, must be called prior to using other authenticated methods
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns response from exchange
     */
    public java.util.concurrent.CompletableFuture<Object> signIn(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            this.checkRequiredCredentials();
            Object request = new java.util.HashMap<String, Object>() {{
                put( "grant_type", "client_credentials" );
            }};
            Object response = (this.accountsPostToken(this.extend(request, parameters))).join();
            //
            //     {
            //         "access_token": "0ttDv/2hTTn3bLi8GP1gKaneiEQ6+0hOBenPrxNQt2s=",
            //         "token_type": "bearer",
            //         "expires_in": 900
            //     }
            //
            Object expiresIn = this.safeInteger(response, "expires_in");
            Object accessToken = this.safeString(response, "access_token");
            Helpers.addElementToObject(this.options, "accessToken", accessToken);
            Helpers.addElementToObject(this.options, "expires", this.sum(this.milliseconds(), Helpers.multiply(expiresIn, 1000)));
            return response;
        }, io.github.ccxt.Exchange.VIRTUAL_EXECUTOR);

    }

    public Object handleErrors(Object code, Object reason, Object url, Object method, Object headers, Object body, Object response, Object requestHeaders, Object requestBody)
    {
        if (Helpers.isTrue(Helpers.isEqual(response, null)))
        {
            return null;  // fallback to default error handler
        }
        if (Helpers.isTrue(Helpers.inOp(response, "errorCode")))
        {
            Object errorCode = this.safeString(response, "errorCode");
            if (Helpers.isTrue(!Helpers.isEqual(errorCode, null)))
            {
                Object errMessage = this.safeString(response, "message", "");
                Object details = this.safeValue(response, "details");
                Object feedback = Helpers.add(Helpers.add(Helpers.add(Helpers.add(Helpers.add(Helpers.add(this.id, " "), errorCode), " "), errMessage), " "), this.json(details));
                if (Helpers.isTrue(Helpers.inOp(this.exceptions, "exact")))
                {
                    this.throwExactlyMatchedException(Helpers.GetValue(this.exceptions, "exact"), errorCode, feedback);
                }
                if (Helpers.isTrue(Helpers.inOp(this.exceptions, "broad")))
                {
                    this.throwBroadlyMatchedException(Helpers.GetValue(this.exceptions, "broad"), errMessage, feedback);
                }
                throw new ExchangeError((String)feedback) ;
            }
        }
        return null;
    }
